/** UsptBsnsSlctnDao.insert */
insert into uspt_bsns_slctn
	(
		bsns_slctn_id
		, last_slctn_trget_id
		, total_wct
		, sport_budget
		, alotm_cash
		, alotm_acthng
		, creator_id
		, created_dt
	) values (
		#{bsnsSlctnId}
		, #{lastSlctnTrgetId}
		, #{totalWct}
		, #{sportBudget}
		, #{alotmCash}
		, #{alotmActhng}
		, #{creatorId}
		, #{createdDt}
	)
